"use strict";parserFactory.register("m.chinesefantasynovels.com",()=>new ChineseFantasyNovelsParser);class ChineseFantasyNovelsParser extends Parser{constructor(){super()}getChapterUrls(e){let t=e.querySelector("dl.chapterlist");return Promise.resolve(util.hyperlinksToChapterList(t).reverse())}findContent(e){return e.querySelector("div#BookText")}extractTitleImpl(e){return e.querySelector("div.btitle h1")}extractAuthor(e){let t=e.querySelector("div.status");if(null!=t){let e="Author:",r=t.textContent;if(r.startsWith(e))return r.substring(e.length)}return super.extractAuthor(e)}removeUnwantedElementsFromContentElement(e){for(let t of e.querySelectorAll("div.ads, div.link, div.adsb"))t.remove();super.removeUnwantedElementsFromContentElement(e)}findChapterTitle(e){return e.querySelector("div#BookCon h1")}}